import{_ as s,o as a,c as n,aw as o}from"./chunks/framework.Dq2onT5h.js";const l=JSON.parse('{"title":"JavaScript Client","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"JavaScript Client | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"ev-reth/js-client.md","filePath":"ev-reth/js-client.md","lastUpdated":1779882971000}');const p=s({name:"ev-reth/js-client.md"},[["render",function(s,l,p,e,t,c){return a(),n("div",null,[...l[0]||(l[0]=[o('<h1 id="javascript-client" tabindex="-1">JavaScript Client <a class="header-anchor" href="#javascript-client" aria-label="Permalink to &quot;JavaScript Client&quot;">​</a></h1><p><code>@evstack/evnode-viem</code> is a Viem-based client for EvNode transaction type <code>0x76</code>. It builds, signs, sponsors, serializes, and sends sponsored batch transactions to ev-reth.</p><p>Use it when your application needs:</p><ul><li>Sponsored gas, where an application account pays transaction fees.</li><li>Batched calls, where several EVM operations execute atomically.</li><li>Direct encoding and decoding of <code>0x76</code> raw transactions.</li></ul><h2 id="install" tabindex="-1">Install <a class="header-anchor" href="#install" aria-label="Permalink to &quot;Install&quot;">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">pnpm</span><span style="color:#BFF3C2;"> add</span><span style="color:#BFF3C2;"> @evstack/evnode-viem</span><span style="color:#BFF3C2;"> viem</span></span></code></pre></div><h2 id="create-a-client" tabindex="-1">Create a Client <a class="header-anchor" href="#create-a-client" aria-label="Permalink to &quot;Create a Client&quot;">​</a></h2><p><code>createEvnodeClient</code> wraps a Viem client. The signer must implement <code>signHash(hash)</code>, and that function must sign the raw 32-byte digest without adding an EIP-191 prefix.</p><div class="language-typescript"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B8A6FF;">import</span><span style="color:#767676;"> {</span><span style="color:#DBD7CA;"> createClient</span><span style="color:#767676;">,</span><span style="color:#DBD7CA;"> http </span><span style="color:#767676;">}</span><span style="color:#B8A6FF;"> from</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">viem</span><span style="color:#BFF3C280;">&#39;</span></span>\n<span class="line"><span style="color:#B8A6FF;">import</span><span style="color:#767676;"> {</span><span style="color:#DBD7CA;"> privateKeyToAccount</span><span style="color:#767676;">,</span><span style="color:#DBD7CA;"> sign </span><span style="color:#767676;">}</span><span style="color:#B8A6FF;"> from</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">viem/accounts</span><span style="color:#BFF3C280;">&#39;</span></span>\n<span class="line"><span style="color:#B8A6FF;">import</span><span style="color:#767676;"> {</span><span style="color:#DBD7CA;"> createEvnodeClient </span><span style="color:#767676;">}</span><span style="color:#B8A6FF;"> from</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">@evstack/evnode-viem</span><span style="color:#BFF3C280;">&#39;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#B8A6FF;">const</span><span style="color:#DBD7CA;"> rpcUrl</span><span style="color:#767676;"> =</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">http://localhost:8545</span><span style="color:#BFF3C280;">&#39;</span></span>\n<span class="line"><span style="color:#B8A6FF;">const</span><span style="color:#DBD7CA;"> privateKey</span><span style="color:#767676;"> =</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">0x...</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#B8A6FF;"> as</span><span style="color:#B8A6FF;"> const</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#B8A6FF;">const</span><span style="color:#DBD7CA;"> client</span><span style="color:#767676;"> =</span><span style="color:#94EEFF;"> createClient</span><span style="color:#767676;">({</span></span>\n<span class="line"><span style="color:#94EEFF;">  transport</span><span style="color:#767676;">: </span><span style="color:#94EEFF;">http</span><span style="color:#767676;">(</span><span style="color:#DBD7CA;">rpcUrl</span><span style="color:#767676;">),</span></span>\n<span class="line"><span style="color:#767676;">})</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#B8A6FF;">const</span><span style="color:#DBD7CA;"> account</span><span style="color:#767676;"> =</span><span style="color:#94EEFF;"> privateKeyToAccount</span><span style="color:#767676;">(</span><span style="color:#DBD7CA;">privateKey</span><span style="color:#767676;">)</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#B8A6FF;">const</span><span style="color:#DBD7CA;"> evnode</span><span style="color:#767676;"> =</span><span style="color:#94EEFF;"> createEvnodeClient</span><span style="color:#767676;">({</span></span>\n<span class="line"><span style="color:#DBD7CA;">  client</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF;">  executor</span><span style="color:#767676;">: {</span></span>\n<span class="line"><span style="color:#94EEFF;">    address</span><span style="color:#767676;">: </span><span style="color:#DBD7CA;">account</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">address</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF;">    signHash</span><span style="color:#767676;">: </span><span style="color:#B8A6FF;">async</span><span style="color:#767676;"> (</span><span style="color:#DBD7CA;">hash</span><span style="color:#767676;">) =&gt; </span><span style="color:#94EEFF;">sign</span><span style="color:#767676;">({ </span><span style="color:#DBD7CA;">hash</span><span style="color:#767676;">, </span><span style="color:#DBD7CA;">privateKey</span><span style="color:#767676;"> }),</span></span>\n<span class="line"><span style="color:#767676;">  },</span></span>\n<span class="line"><span style="color:#767676;">})</span></span></code></pre></div><h2 id="send-a-batch" tabindex="-1">Send a Batch <a class="header-anchor" href="#send-a-batch" aria-label="Permalink to &quot;Send a Batch&quot;">​</a></h2><p>Each call has <code>to</code>, <code>value</code>, and <code>data</code>. Use <code>to: null</code> only for the first call when deploying a contract.</p><div class="language-typescript"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B8A6FF;">const</span><span style="color:#DBD7CA;"> txHash</span><span style="color:#767676;"> =</span><span style="color:#B8A6FF;"> await</span><span style="color:#DBD7CA;"> evnode</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">send</span><span style="color:#767676;">({</span></span>\n<span class="line"><span style="color:#94EEFF;">  calls</span><span style="color:#767676;">: [</span></span>\n<span class="line"><span style="color:#767676;">    { </span><span style="color:#94EEFF;">to</span><span style="color:#767676;">: </span><span style="color:#DBD7CA;">recipient1</span><span style="color:#767676;">, </span><span style="color:#94EEFF;">value</span><span style="color:#767676;">: </span><span style="color:#FFECB6;">1_000_000_000_000_000</span><span style="color:#B8A6FF;">n</span><span style="color:#767676;">, </span><span style="color:#94EEFF;">data</span><span style="color:#767676;">: </span><span style="color:#BFF3C280;">&#39;</span><span style="color:#BFF3C2;">0x</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#767676;"> },</span></span>\n<span class="line"><span style="color:#767676;">    { </span><span style="color:#94EEFF;">to</span><span style="color:#767676;">: </span><span style="color:#DBD7CA;">recipient2</span><span style="color:#767676;">, </span><span style="color:#94EEFF;">value</span><span style="color:#767676;">: </span><span style="color:#FFECB6;">1_000_000_000_000_000</span><span style="color:#B8A6FF;">n</span><span style="color:#767676;">, </span><span style="color:#94EEFF;">data</span><span style="color:#767676;">: </span><span style="color:#BFF3C280;">&#39;</span><span style="color:#BFF3C2;">0x</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#767676;"> },</span></span>\n<span class="line"><span style="color:#767676;">  ],</span></span>\n<span class="line"><span style="color:#767676;">})</span></span></code></pre></div><p>If either transfer fails, ev-reth reverts the whole transaction.</p><h2 id="sponsor-a-transaction" tabindex="-1">Sponsor a Transaction <a class="header-anchor" href="#sponsor-a-transaction" aria-label="Permalink to &quot;Sponsor a Transaction&quot;">​</a></h2><p>Use <code>createIntent</code> when the executor signs first and a sponsor signs later.</p><div class="language-typescript"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B8A6FF;">import</span><span style="color:#767676;"> {</span><span style="color:#DBD7CA;"> createClient</span><span style="color:#767676;">,</span><span style="color:#DBD7CA;"> http </span><span style="color:#767676;">}</span><span style="color:#B8A6FF;"> from</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">viem</span><span style="color:#BFF3C280;">&#39;</span></span>\n<span class="line"><span style="color:#B8A6FF;">import</span><span style="color:#767676;"> {</span><span style="color:#DBD7CA;"> privateKeyToAccount</span><span style="color:#767676;">,</span><span style="color:#DBD7CA;"> sign </span><span style="color:#767676;">}</span><span style="color:#B8A6FF;"> from</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">viem/accounts</span><span style="color:#BFF3C280;">&#39;</span></span>\n<span class="line"><span style="color:#B8A6FF;">import</span><span style="color:#767676;"> {</span><span style="color:#DBD7CA;"> createEvnodeClient </span><span style="color:#767676;">}</span><span style="color:#B8A6FF;"> from</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">@evstack/evnode-viem</span><span style="color:#BFF3C280;">&#39;</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#B8A6FF;">const</span><span style="color:#DBD7CA;"> client</span><span style="color:#767676;"> =</span><span style="color:#94EEFF;"> createClient</span><span style="color:#767676;">({ </span><span style="color:#94EEFF;">transport</span><span style="color:#767676;">: </span><span style="color:#94EEFF;">http</span><span style="color:#767676;">(</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#BFF3C2;">http://localhost:8545</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#767676;">) })</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#B8A6FF;">const</span><span style="color:#DBD7CA;"> executorKey</span><span style="color:#767676;"> =</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">0x...</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#B8A6FF;"> as</span><span style="color:#B8A6FF;"> const</span></span>\n<span class="line"><span style="color:#B8A6FF;">const</span><span style="color:#DBD7CA;"> sponsorKey</span><span style="color:#767676;"> =</span><span style="color:#BFF3C280;"> &#39;</span><span style="color:#BFF3C2;">0x...</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#B8A6FF;"> as</span><span style="color:#B8A6FF;"> const</span></span>\n<span class="line"><span style="color:#B8A6FF;">const</span><span style="color:#DBD7CA;"> executor</span><span style="color:#767676;"> =</span><span style="color:#94EEFF;"> privateKeyToAccount</span><span style="color:#767676;">(</span><span style="color:#DBD7CA;">executorKey</span><span style="color:#767676;">)</span></span>\n<span class="line"><span style="color:#B8A6FF;">const</span><span style="color:#DBD7CA;"> sponsor</span><span style="color:#767676;"> =</span><span style="color:#94EEFF;"> privateKeyToAccount</span><span style="color:#767676;">(</span><span style="color:#DBD7CA;">sponsorKey</span><span style="color:#767676;">)</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#B8A6FF;">const</span><span style="color:#DBD7CA;"> evnode</span><span style="color:#767676;"> =</span><span style="color:#94EEFF;"> createEvnodeClient</span><span style="color:#767676;">({</span></span>\n<span class="line"><span style="color:#DBD7CA;">  client</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF;">  executor</span><span style="color:#767676;">: {</span></span>\n<span class="line"><span style="color:#94EEFF;">    address</span><span style="color:#767676;">: </span><span style="color:#DBD7CA;">executor</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">address</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF;">    signHash</span><span style="color:#767676;">: </span><span style="color:#B8A6FF;">async</span><span style="color:#767676;"> (</span><span style="color:#DBD7CA;">hash</span><span style="color:#767676;">) =&gt; </span><span style="color:#94EEFF;">sign</span><span style="color:#767676;">({ </span><span style="color:#DBD7CA;">hash</span><span style="color:#767676;">, </span><span style="color:#94EEFF;">privateKey</span><span style="color:#767676;">: </span><span style="color:#DBD7CA;">executorKey</span><span style="color:#767676;"> }),</span></span>\n<span class="line"><span style="color:#767676;">  },</span></span>\n<span class="line"><span style="color:#94EEFF;">  sponsor</span><span style="color:#767676;">: {</span></span>\n<span class="line"><span style="color:#94EEFF;">    address</span><span style="color:#767676;">: </span><span style="color:#DBD7CA;">sponsor</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">address</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF;">    signHash</span><span style="color:#767676;">: </span><span style="color:#B8A6FF;">async</span><span style="color:#767676;"> (</span><span style="color:#DBD7CA;">hash</span><span style="color:#767676;">) =&gt; </span><span style="color:#94EEFF;">sign</span><span style="color:#767676;">({ </span><span style="color:#DBD7CA;">hash</span><span style="color:#767676;">, </span><span style="color:#94EEFF;">privateKey</span><span style="color:#767676;">: </span><span style="color:#DBD7CA;">sponsorKey</span><span style="color:#767676;"> }),</span></span>\n<span class="line"><span style="color:#767676;">  },</span></span>\n<span class="line"><span style="color:#767676;">})</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#B8A6FF;">const</span><span style="color:#DBD7CA;"> intent</span><span style="color:#767676;"> =</span><span style="color:#B8A6FF;"> await</span><span style="color:#DBD7CA;"> evnode</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">createIntent</span><span style="color:#767676;">({</span></span>\n<span class="line"><span style="color:#94EEFF;">  calls</span><span style="color:#767676;">: [</span></span>\n<span class="line"><span style="color:#767676;">    { </span><span style="color:#94EEFF;">to</span><span style="color:#767676;">: </span><span style="color:#DBD7CA;">executor</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">address</span><span style="color:#767676;">, </span><span style="color:#94EEFF;">value</span><span style="color:#767676;">: </span><span style="color:#FFECB6;">0</span><span style="color:#B8A6FF;">n</span><span style="color:#767676;">, </span><span style="color:#94EEFF;">data</span><span style="color:#767676;">: </span><span style="color:#BFF3C280;">&#39;</span><span style="color:#BFF3C2;">0x</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#767676;"> },</span></span>\n<span class="line"><span style="color:#767676;">  ],</span></span>\n<span class="line"><span style="color:#767676;">})</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#B8A6FF;">const</span><span style="color:#DBD7CA;"> txHash</span><span style="color:#767676;"> =</span><span style="color:#B8A6FF;"> await</span><span style="color:#DBD7CA;"> evnode</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">sponsorAndSend</span><span style="color:#767676;">({ </span><span style="color:#DBD7CA;">intent</span><span style="color:#767676;"> })</span></span></code></pre></div><p>The executor remains the transaction sender. The sponsor pays gas and receives gas refunds.</p><h2 id="manual-parameters" tabindex="-1">Manual Parameters <a class="header-anchor" href="#manual-parameters" aria-label="Permalink to &quot;Manual Parameters&quot;">​</a></h2><p>If omitted, the client resolves <code>chainId</code>, <code>nonce</code>, <code>maxFeePerGas</code>, <code>maxPriorityFeePerGas</code>, <code>gasLimit</code>, and <code>accessList</code> from the RPC endpoint or local defaults.</p><p>Override them when your application already has fee estimates or nonce management:</p><div class="language-typescript"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B8A6FF;">await</span><span style="color:#DBD7CA;"> evnode</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">send</span><span style="color:#767676;">({</span></span>\n<span class="line"><span style="color:#94EEFF;">  calls</span><span style="color:#767676;">: [</span></span>\n<span class="line"><span style="color:#767676;">    { </span><span style="color:#94EEFF;">to</span><span style="color:#767676;">: </span><span style="color:#DBD7CA;">account</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">address</span><span style="color:#767676;">, </span><span style="color:#94EEFF;">value</span><span style="color:#767676;">: </span><span style="color:#FFECB6;">0</span><span style="color:#B8A6FF;">n</span><span style="color:#767676;">, </span><span style="color:#94EEFF;">data</span><span style="color:#767676;">: </span><span style="color:#BFF3C280;">&#39;</span><span style="color:#BFF3C2;">0x</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#767676;"> },</span></span>\n<span class="line"><span style="color:#767676;">  ],</span></span>\n<span class="line"><span style="color:#94EEFF;">  nonce</span><span style="color:#767676;">: </span><span style="color:#FFECB6;">12</span><span style="color:#B8A6FF;">n</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF;">  gasLimit</span><span style="color:#767676;">: </span><span style="color:#FFECB6;">100_000</span><span style="color:#B8A6FF;">n</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF;">  maxFeePerGas</span><span style="color:#767676;">: </span><span style="color:#FFECB6;">1_000_000_000</span><span style="color:#B8A6FF;">n</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF;">  maxPriorityFeePerGas</span><span style="color:#767676;">: </span><span style="color:#FFECB6;">0</span><span style="color:#B8A6FF;">n</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF;">  accessList</span><span style="color:#767676;">: [],</span></span>\n<span class="line"><span style="color:#767676;">})</span></span></code></pre></div><h2 id="application-sponsor-service" tabindex="-1">Application Sponsor Service <a class="header-anchor" href="#application-sponsor-service" aria-label="Permalink to &quot;Application Sponsor Service&quot;">​</a></h2><p>Applications can hide sponsor keys behind a JSON-RPC proxy. The proxy receives <code>eth_sendRawTransaction</code>, detects unsigned type <code>0x76</code> transactions, validates the app policy, adds <code>feePayerSignature</code>, and forwards the sponsored raw transaction to ev-reth.</p><p>The ev-reth repository includes this pattern under <code>bin/sponsor-service</code>.</p><p>Expected proxy behavior:</p><ul><li>Forward ordinary JSON-RPC requests unchanged.</li><li>Intercept <code>eth_sendRawTransaction</code> only when the raw transaction starts with type byte <code>0x76</code>.</li><li>Forward already-sponsored transactions unchanged.</li><li>Reject intents that fail policy checks, such as wrong chain ID, high gas limit, high max fee, or low sponsor balance.</li></ul><p>Client-side code can then point Viem at the sponsor service instead of the node:</p><div class="language-typescript"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B8A6FF;">const</span><span style="color:#DBD7CA;"> client</span><span style="color:#767676;"> =</span><span style="color:#94EEFF;"> createClient</span><span style="color:#767676;">({</span></span>\n<span class="line"><span style="color:#94EEFF;">  transport</span><span style="color:#767676;">: </span><span style="color:#94EEFF;">http</span><span style="color:#767676;">(</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#BFF3C2;">http://localhost:3000</span><span style="color:#BFF3C280;">&#39;</span><span style="color:#767676;">),</span></span>\n<span class="line"><span style="color:#767676;">})</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#B8A6FF;">const</span><span style="color:#DBD7CA;"> evnode</span><span style="color:#767676;"> =</span><span style="color:#94EEFF;"> createEvnodeClient</span><span style="color:#767676;">({</span></span>\n<span class="line"><span style="color:#DBD7CA;">  client</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF;">  executor</span><span style="color:#767676;">: {</span></span>\n<span class="line"><span style="color:#94EEFF;">    address</span><span style="color:#767676;">: </span><span style="color:#DBD7CA;">executor</span><span style="color:#767676;">.</span><span style="color:#DBD7CA;">address</span><span style="color:#767676;">,</span></span>\n<span class="line"><span style="color:#94EEFF;">    signHash</span><span style="color:#767676;">: </span><span style="color:#B8A6FF;">async</span><span style="color:#767676;"> (</span><span style="color:#DBD7CA;">hash</span><span style="color:#767676;">) =&gt; </span><span style="color:#94EEFF;">sign</span><span style="color:#767676;">({ </span><span style="color:#DBD7CA;">hash</span><span style="color:#767676;">, </span><span style="color:#94EEFF;">privateKey</span><span style="color:#767676;">: </span><span style="color:#DBD7CA;">executorKey</span><span style="color:#767676;"> }),</span></span>\n<span class="line"><span style="color:#767676;">  },</span></span>\n<span class="line"><span style="color:#767676;">})</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#B8A6FF;">const</span><span style="color:#DBD7CA;"> txHash</span><span style="color:#767676;"> =</span><span style="color:#B8A6FF;"> await</span><span style="color:#DBD7CA;"> evnode</span><span style="color:#767676;">.</span><span style="color:#94EEFF;">send</span><span style="color:#767676;">({</span></span>\n<span class="line"><span style="color:#94EEFF;">  calls</span><span style="color:#767676;">: [</span></span>\n<span class="line"><span style="color:#767676;">    { </span><span style="color:#DBD7CA;">to</span><span style="color:#767676;">, </span><span style="color:#DBD7CA;">value</span><span style="color:#767676;">, </span><span style="color:#DBD7CA;">data</span><span style="color:#767676;"> },</span></span>\n<span class="line"><span style="color:#767676;">  ],</span></span>\n<span class="line"><span style="color:#767676;">})</span></span></code></pre></div><p>In this setup the executor signs the intent, while the sponsor service adds the sponsor signature before forwarding to ev-reth.</p><h2 id="utilities" tabindex="-1">Utilities <a class="header-anchor" href="#utilities" aria-label="Permalink to &quot;Utilities&quot;">​</a></h2><p>The package also exports lower-level helpers:</p><table tabindex="0"><thead><tr><th>Helper</th><th>Use</th></tr></thead><tbody><tr><td><code>encodeSignedTransaction</code></td><td>Serialize an EvNode signed transaction</td></tr><tr><td><code>decodeEvNodeTransaction</code></td><td>Decode a type <code>0x76</code> raw transaction</td></tr><tr><td><code>computeExecutorSigningHash</code></td><td>Compute the executor digest</td></tr><tr><td><code>computeSponsorSigningHash</code></td><td>Compute the sponsor digest</td></tr><tr><td><code>computeTxHash</code></td><td>Compute the transaction hash</td></tr><tr><td><code>recoverExecutor</code></td><td>Recover the executor address</td></tr><tr><td><code>recoverSponsor</code></td><td>Recover the sponsor address</td></tr><tr><td><code>estimateIntrinsicGas</code></td><td>Estimate the minimum intrinsic gas for calls</td></tr><tr><td><code>validateEvNodeTx</code></td><td>Validate local call-list constraints</td></tr></tbody></table><h2 id="related-docs" tabindex="-1">Related Docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related Docs&quot;">​</a></h2><ul><li><a href="/ev-reth/features/sponsored-transactions">Sponsored Batch Transactions</a></li><li><a href="/ev-reth/overview">ev-reth Overview</a></li><li><a href="/getting-started/evm/quickstart">EVM Quickstart</a></li></ul>',34)])])}]]);export{l as __pageData,p as default};
